  try {
    // Input validation: only allow whitelisted query params
    const { page = 1, limit = 10 } = req.query;

    const parsedPage = parseInt(page, 10);
    const parsedLimit = parseInt(limit, 10);

    if (
      isNaN(parsedPage) || parsedPage < 1 ||
      isNaN(parsedLimit) || parsedLimit < 1 || parsedLimit > 100
    ) {
      return res.status(400).json({ error: 'Invalid pagination parameters.' });
    }

    // In a real app: fetch from DB with parameterized queries
    const users = [
      { id: 1, name: 'Alice', email: 'alice@example.com' },
      { id: 2, name: 'Bob',   email: 'bob@example.com'   },
    ];

    res.json({ data: users, page: parsedPage, limit: parsedLimit });
  } catch (err) {
    next(err); // Forward unexpected errors to the error handler
  }
});

// ── 404 handler ───────────────────────────────────────────────────────────────
app.use((req, res) => {
  res.status(404).json({ error: 'Not found.' });
});

// ── Centralized error handler ─────────────────────────────────────────────────
// Must be defined last and have exactly 4 parameters (err, req, res, next)
app.use((err, req, res, next) => { // eslint-disable-line no-unused-vars
  const isDev = process.env.NODE_ENV !== 'production';

